	static constexpr auto rule(rx_flags, lparen) -> ctll::push<ctll::anything, open_group, new_branch, exp_atoms>;
	static constexpr auto rule(rx_flags, rparen) -> ctll::push<ctll::anything, close_group, exp_atoms>;
	static constexpr auto rule(rx_flags, lbracket) -> ctll::push<ctll::anything, open_maybe, new_branch, exp_atoms>;
	static constexpr auto rule(rx_flags, rbracket) -> ctll::push<ctll::anything, close_maybe, exp_atoms>;
	static constexpr auto rule(rx_flags, quote) -> ctll::push<ctll::anything, begin_string, string_body>;
	static constexpr auto rule(rx_flags, slash) -> ctll::push<ctll::anything, regex_or_comment>;
	static constexpr auto rule(rx_flags, newline) -> ctll::push<ctll::anything, branch, skip, exp_after_nl>;
	static constexpr auto rule(rx_flags, exclamation_mark__percent) -> ctll::epsilon;
	static constexpr auto rule(rx_flags, ctll::epsilon) -> ctll::epsilon;

	static constexpr auto rule(rx_class_open, caret) -> ctll::push<ctll::anything, open_class, mark_class_neg, cls_first>;
	static constexpr auto rule(rx_class_open, minus__backslash__sclose) -> ctll::push<open_class, cls_first_pos>;
	static constexpr auto rule(rx_class_open, cls_char) -> ctll::push<open_class, cls_first_pos>;

