	static constexpr auto rule(cls_range_escape, x) -> ctll::push<ctll::anything, hexdig, push_hex_high, hexdig, cls_range_hex_char, cls_after_range>;
	static constexpr auto rule(cls_range_escape, minus__sopen__backslash__sclose__caret) -> ctll::push<ctll::anything, cls_range_esc_char, cls_after_range>;

	static constexpr auto rule(statement, i) -> ctll::push<ctll::anything, statement_i>;

	static constexpr auto rule(statement_i, g) -> ctll::push<ctll::anything, n, o, r, e, mark_ignore, new_branch, ws, exp_atoms>;
	static constexpr auto rule(statement_i, m) -> ctll::push<ctll::anything, p, o, r, t, mark_import, ws1, import_path>;

	static constexpr auto rule(ws1, inline_ws) -> ctll::push<ctll::anything, ws>;

	static constexpr auto rule(import_path, uscore) -> ctll::push<ctll::anything, begin_name, push_name_char, import_seg_run>;
	static constexpr auto rule(import_path, set_4) -> ctll::push<ctll::anything, begin_name, push_name_char, import_seg_lc>;
