	static constexpr auto rule(import_alias_lc, set_24) -> ctll::push<import_alias, line_end>;
	static constexpr auto rule(import_alias_lc, ctll::epsilon) -> ctll::push<import_alias, line_end>;

	static constexpr auto rule(import_alias_uc, set_8) -> ctll::push<ctll::anything, push_name_char, import_alias_uc>;
