	static constexpr auto rule(rx_class_open, cls_char) -> ctll::push<open_class, cls_first_pos>;

	static constexpr auto rule(cls_first, rbracket) -> ctll::push<ctll::anything, cls_push_rbracket, cls_items>;
	static constexpr auto rule(cls_first, minus__caret) -> ctll::push<ctll::anything, cls_push_char, cls_after_char>;
	static constexpr auto rule(cls_first, cls_char) -> ctll::push<ctll::anything, cls_push_char, cls_after_char>;
	static constexpr auto rule(cls_first, backslash) -> ctll::push<ctll::anything, cls_escape>;

	static constexpr auto rule(cls_first_pos, rbracket) -> ctll::push<ctll::anything, cls_push_rbracket, cls_items>;
	static constexpr auto rule(cls_first_pos, minus) -> ctll::push<ctll::anything, cls_push_char, cls_after_char>;
