	static constexpr auto rule(cls_first_pos, backslash) -> ctll::push<ctll::anything, cls_escape>;

	static constexpr auto rule(cls_items, caret) -> ctll::push<ctll::anything, cls_push_char, cls_after_char>;
	static constexpr auto rule(cls_items, cls_char) -> ctll::push<ctll::anything, cls_push_char, cls_after_char>;
	static constexpr auto rule(cls_items, backslash) -> ctll::push<ctll::anything, cls_escape>;
