	static constexpr auto rule(import_seg_run, uscore) -> ctll::push<ctll::anything, push_name_char, import_seg_run>;
	static constexpr auto rule(import_seg_run, set_4) -> ctll::push<ctll::anything, push_name_char, import_seg_lc>;
	static constexpr auto rule(import_seg_run, set_5) -> ctll::push<ctll::anything, push_name_char, import_seg_uc>;

	static constexpr auto rule(import_seg_lc, set_7) -> ctll::push<ctll::anything, push_name_char, import_seg_lc>;
	static constexpr auto rule(import_seg_lc, set_22) -> ctll::push<import_seg, import_post>;
