	static constexpr auto rule(import_seg_uc, ctll::epsilon) -> ctll::push<import_seg, import_post>;

	static constexpr auto rule(import_post, dot) -> ctll::push<ctll::anything, import_path>;
	static constexpr auto rule(import_post, inline_ws) -> ctll::push<ctll::anything, import_post2>;
	static constexpr auto rule(import_post, newline) -> ctll::push<ctll::anything, skip>;
	static constexpr auto rule(import_post, slash) -> ctll::push<ctll::anything, slash, comment_tail>;
	static constexpr auto rule(import_post, set_2) -> ctll::epsilon;
	static constexpr auto rule(import_post, ctll::epsilon) -> ctll::epsilon;

	static constexpr auto rule(import_post2, inline_ws) -> ctll::push<ctll::anything, import_post2>;
