	static constexpr auto rule(import_post2, lparen) -> ctll::push<ctll::anything, ws, import_list_name>;
	static constexpr auto rule(import_post2, newline) -> ctll::push<ctll::anything, skip>;
	static constexpr auto rule(import_post2, slash) -> ctll::push<ctll::anything, slash, comment_tail>;
	static constexpr auto rule(import_post2, set_2) -> ctll::epsilon;
	static constexpr auto rule(import_post2, ctll::epsilon) -> ctll::epsilon;

	static constexpr auto rule(import_alias_name, uscore) -> ctll::push<ctll::anything, begin_name, push_name_char, import_alias_run>;
	static constexpr auto rule(import_alias_name, set_4) -> ctll::push<ctll::anything, begin_name, push_name_char, import_alias_lc>;
	static constexpr auto rule(import_alias_name, set_5) -> ctll::push<ctll::anything, begin_name, push_name_char, import_alias_uc>;

